import React, { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { api } from "../lib/api";
import { 
  Plus, 
  Trash2, 
  Search, 
  Package,
  AlertCircle
} from "lucide-react";
import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

interface BOMItem {
  product_id: string;
  product_name: string;
  quantity: number;
}

interface BOMBuilderProps {
  items: BOMItem[];
  onChange: (items: BOMItem[]) => void;
  excludeProductId?: string;
}

export default function BOMBuilder({ items, onChange, excludeProductId }: BOMBuilderProps) {
  const [searchTerm, setSearchTerm] = useState("");
  const currentCompanyId = api.getCompanyId();

  const { data: products = [] } = useQuery({ 
    queryKey: ["products", currentCompanyId], 
    queryFn: () => api.get("products"),
  });

  const filteredProducts = useMemo(() => {
    return products.filter((p: any) => 
      p.id !== excludeProductId &&
      !items.some(item => item.product_id === p.id) &&
      (p.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
       p.sku?.toLowerCase().includes(searchTerm.toLowerCase()))
    ).slice(0, 5);
  }, [products, searchTerm, items, excludeProductId]);

  const addItem = (product: any) => {
    onChange([...items, { 
      product_id: product.id, 
      product_name: product.name, 
      quantity: 1 
    }]);
    setSearchTerm("");
  };

  const removeItem = (productId: string) => {
    onChange(items.filter(item => item.product_id !== productId));
  };

  const updateQuantity = (productId: string, quantity: number) => {
    if (quantity < 0.001) return;
    onChange(items.map(item => 
      item.product_id === productId ? { ...item, quantity } : item
    ));
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-bold text-gray-700 uppercase tracking-wider">Composição do Kit (BOM)</h3>
        <p className="text-[10px] text-gray-400 font-medium">Estoque será baixado dos componentes</p>
      </div>

      {/* Search and Add */}
      <div className="relative">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input 
            type="text" 
            placeholder="Buscar componentes para adicionar..." 
            className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-blue-500"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        {searchTerm.length > 0 && (
          <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-100 rounded-xl shadow-xl z-10 overflow-hidden">
            {filteredProducts.length === 0 ? (
              <div className="p-4 text-center text-xs text-gray-400">Nenhum produto encontrado</div>
            ) : (
              <div className="divide-y divide-gray-50">
                {filteredProducts.map((p: any) => (
                  <button
                    key={p.id}
                    type="button"
                    onClick={() => addItem(p)}
                    className="w-full flex items-center justify-between p-3 hover:bg-blue-50 transition-colors text-left"
                  >
                    <div className="flex items-center gap-3">
                      <div className="p-1.5 bg-gray-100 text-gray-500 rounded-lg">
                        <Package size={14} />
                      </div>
                      <div>
                        <p className="text-xs font-bold text-gray-900">{p.name}</p>
                        <p className="text-[10px] text-gray-500">Estoque: {p.stock_quantity} {p.unit}</p>
                      </div>
                    </div>
                    <Plus size={16} className="text-blue-600" />
                  </button>
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      {/* Items List */}
      <div className="space-y-2">
        {items.length === 0 ? (
          <div className="p-8 border-2 border-dashed border-gray-100 rounded-2xl text-center">
            <Package size={32} className="mx-auto mb-2 text-gray-200" />
            <p className="text-xs text-gray-400">Este produto não é um kit. Adicione componentes para torná-lo um.</p>
          </div>
        ) : (
          <div className="bg-white border border-gray-100 rounded-2xl overflow-hidden">
            <table className="w-full text-left text-xs">
              <thead className="bg-gray-50 text-gray-500 uppercase font-bold">
                <tr>
                  <th className="px-4 py-2">Componente</th>
                  <th className="px-4 py-2 w-24">Qtd</th>
                  <th className="px-4 py-2 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {items.map((item) => (
                  <tr key={item.product_id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-3">
                      <p className="font-bold text-gray-900">{item.product_name}</p>
                    </td>
                    <td className="px-4 py-3">
                      <input 
                        type="number" 
                        step="0.001"
                        value={item.quantity}
                        onChange={(e) => updateQuantity(item.product_id, parseFloat(e.target.value) || 0)}
                        className="w-full px-2 py-1 bg-gray-50 border border-gray-100 rounded focus:ring-1 focus:ring-blue-500 outline-none font-bold text-blue-600"
                      />
                    </td>
                    <td className="px-4 py-3 text-right">
                      <button 
                        type="button"
                        onClick={() => removeItem(item.product_id)}
                        className="text-red-400 hover:text-red-600 transition-colors"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {items.length > 0 && (
        <div className="p-3 bg-blue-50 rounded-xl flex items-start gap-3">
          <AlertCircle className="text-blue-600 shrink-0" size={16} />
          <p className="text-[10px] text-blue-700 leading-relaxed">
            Ao vender este produto, o sistema baixará automaticamente as quantidades especificadas acima do estoque de cada componente.
          </p>
        </div>
      )}
    </div>
  );
}

import React from 'react';
import { FileText, Table as TableIcon, Download } from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import * as XLSX from 'xlsx';
import { toast } from 'sonner';
import { formatBR, getNowBR } from "../lib/dateUtils";

interface ExportButtonProps {
  data: any[];
  filename: string;
  format: 'pdf' | 'xlsx';
  title?: string;
  headers?: Record<string, string>;
  className?: string;
  summaryBlocks?: {
    label: string;
    value: string;
    isPrimary?: boolean;
  }[];
}

export default function ExportButton({ 
  data, 
  filename, 
  format, 
  title, 
  headers,
  className,
  summaryBlocks
}: ExportButtonProps) {

  const handleExport = () => {
    if (!data || data.length === 0) {
      toast.error("Não há dados para exportar.");
      return;
    }

    // Prepare data based on headers mapping
    const exportData = data.map(item => {
      if (!headers) return item;
      const newItem: any = {};
      Object.entries(headers).forEach(([key, label]) => {
        newItem[label] = item[key];
      });
      return newItem;
    });

    if (format === 'xlsx') {
      exportToExcel(exportData);
    } else {
      exportToPDF(exportData);
    }
  };

  const exportToExcel = (preparedData: any[]) => {
    try {
      const worksheet = XLSX.utils.json_to_sheet(preparedData);
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, "Dados");
      XLSX.writeFile(workbook, `${filename}.xlsx`);
      toast.success("Arquivo Excel gerado com sucesso!");
    } catch (error) {
      console.error("Erro ao exportar Excel:", error);
      toast.error("Erro ao gerar arquivo Excel.");
    }
  };

  const exportToPDF = (preparedData: any[]) => {
    try {
      const doc = new jsPDF();
      let startY = 20;

      if (title) {
        doc.setFontSize(18);
        doc.setTextColor(31, 41, 55);
        doc.text(title, 14, 22);
        doc.setFontSize(11);
        doc.setTextColor(100, 116, 139);
        doc.text(`Gerado em: ${formatBR(getNowBR(), "dd/MM/yyyy HH:mm")}`, 14, 30);
        startY = 35;
      }

      if (summaryBlocks && summaryBlocks.length > 0) {
        const pageWidth = doc.internal.pageSize.getWidth();
        let currentX = pageWidth - 14; 

        // Draw backwards to stack them horizontally on the right
        for (let i = summaryBlocks.length - 1; i >= 0; i--) {
          const block = summaryBlocks[i];

          doc.setFontSize(7);
          doc.setFont("helvetica", "bold");
          const labelWidth = doc.getTextWidth(block.label.toUpperCase());

          doc.setFontSize(9);
          const valueWidth = doc.getTextWidth(block.value);

          const blockWidth = Math.max(labelWidth, valueWidth) + 12; 
          const blockHeight = 14;

          currentX -= blockWidth;

          if (block.isPrimary) {
            doc.setFillColor(37, 99, 235);
          } else {
            doc.setFillColor(243, 244, 246);
          }

          doc.roundedRect(currentX, 15, blockWidth, blockHeight, 1.5, 1.5, 'F');

          if (block.isPrimary) doc.setTextColor(191, 219, 254);
          else doc.setTextColor(156, 163, 175);
          doc.setFontSize(7);
          doc.text(block.label.toUpperCase(), currentX + 6, 20);

          if (block.isPrimary) doc.setTextColor(255, 255, 255);
          else doc.setTextColor(55, 65, 81);
          doc.setFontSize(9);
          doc.text(block.value, currentX + 6, 26);

          currentX -= 4; 
        }

        startY = 40; 
      }

      const tableHeaders = Object.keys(preparedData[0]);
      const tableRows = preparedData.map(item => Object.values(item).map(val => val !== null && val !== undefined ? String(val) : ''));

      autoTable(doc, {
        head: [tableHeaders],
        body: tableRows,
        startY: startY,
        styles: { fontSize: 8, cellPadding: 2 },
        headStyles: { fillColor: [37, 99, 235], textColor: [255, 255, 255] },
        alternateRowStyles: { fillColor: [249, 250, 251] },
      });

      doc.save(`${filename}.pdf`);
      toast.success("Arquivo PDF gerado com sucesso!");
    } catch (error) {
      console.error("Erro ao exportar PDF:", error);
      toast.error("Erro ao gerar arquivo PDF.");
    }
  };

  const Icon = format === 'pdf' ? FileText : TableIcon;
  const label = format === 'pdf' ? 'Exportar PDF' : 'Exportar Excel';
  const bgColor = format === 'pdf' ? 'bg-red-50 text-red-600 hover:bg-red-100' : 'bg-green-50 text-green-600 hover:bg-green-100';

  return (
    <button
      onClick={handleExport}
      className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold transition-all ${bgColor} ${className}`}
    >
      <Icon size={18} />
      <span>{label}</span>
    </button>
  );
}

import React, { useState, useRef } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { api } from "../../lib/api";
import { useAuth } from "../../lib/auth";
import { 
  X, 
  Upload, 
  FileText, 
  CheckCircle2, 
  AlertCircle, 
  ArrowUpRight, 
  ArrowDownLeft,
  ArrowRightLeft,
  Search,
  Plus,
  Check
} from "lucide-react";
import { toast } from "sonner";
import { parse } from "ofx-js";
import { formatBR } from "../../lib/dateUtils";

interface OFXTransaction {
  id: string;
  type: "DEBIT" | "CREDIT";
  date: string;
  amount: number;
  memo: string;
  fitid: string;
}

interface MatchResult {
  match: any;
  score: number;
  reason: string;
  isRuleMatch?: boolean;
}

// Common bank noise to remove for better matching
const BANK_NOISE = [
  'DOC', 'TED', 'PIX', 'PAGTO', 'TRANSF', 'DEPOSITO', 'SAQUE', 'TAR', 'TARIFA',
  'CH', 'CHEQUE', 'LIQ', 'LIQUIDACAO', 'EST', 'ESTORNO', 'REF', 'REFERENTE',
  'CONV', 'CONVENIO', 'COB', 'COBRANCA', 'PG', 'PAG', 'PAGAMENTO'
];

function normalizeDescription(str: string): string {
  let normalized = str.toUpperCase();

  // Remove noise words
  BANK_NOISE.forEach(noise => {
    const regex = new RegExp(`\\b${noise}\\b`, 'g');
    normalized = normalized.replace(regex, '');
  });

  // Remove special characters and extra spaces
  return normalized.replace(/[^A-Z0-9 ]/g, '').replace(/\s+/g, ' ').trim();
}

// Simple string similarity (Dice's Coefficient)
function getStringSimilarity(str1: string, str2: string): number {
  const s1 = normalizeDescription(str1).toLowerCase();
  const s2 = normalizeDescription(str2).toLowerCase();

  if (s1 === s2) return 1;
  if (s1.length < 2 || s2.length < 2) return 0;

  const bigrams1 = new Set();
  for (let i = 0; i < s1.length - 1; i++) {
    bigrams1.add(s1.substring(i, i + 2));
  }

  let intersect = 0;
  for (let i = 0; i < s2.length - 1; i++) {
    const bigram = s2.substring(i, i + 2);
    if (bigrams1.has(bigram)) {
      intersect++;
    }
  }

  return (2 * intersect) / (s1.length + s2.length - 2);
}

interface OFXImporterProps {
  onClose: () => void;
  bankAccountId: string;
  bankAccountName: string;
}

export function OFXImporter({ onClose, bankAccountId, bankAccountName }: OFXImporterProps) {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [transactions, setTransactions] = useState<OFXTransaction[]>([]);
  const [isParsing, setIsParsing] = useState(false);
  const [selectedTransactions, setSelectedTransactions] = useState<Set<string>>(new Set());
  const [manualMatches, setManualMatches] = useState<Record<string, any>>({});
  const [isManualMatching, setIsManualMatching] = useState<string | null>(null);
  const [isSavingRule, setIsSavingRule] = useState<string | null>(null);

  const currentCompanyId = api.getCompanyId();

  // Fetch rules
  const { data: rules = [] } = useQuery({
    queryKey: ["reconciliation_rules", currentCompanyId],
    queryFn: () => api.get("reconciliation_rules"),
    enabled: !!user
  });

  // Fetch existing accounts to match
  const { data: payables = [] } = useQuery({
    queryKey: ["accountsPayable", currentCompanyId],
    queryFn: () => api.get("accountsPayable"),
    enabled: transactions.length > 0
  });

  const { data: receivables = [] } = useQuery({
    queryKey: ["accountsReceivable", currentCompanyId],
    queryFn: () => api.get("accountsReceivable"),
    enabled: transactions.length > 0
  });

  const findBestMatch = (t: OFXTransaction, existing: any[]): MatchResult | null => {
    let bestMatch: MatchResult | null = null;
    const isExpense = t.type === "DEBIT";

    // 1. Check Rules first to get a "boost" or "category hint"
    const matchingRule = rules.find((r: any) => {
      if (r.target_type !== (isExpense ? 'PAYABLE' : 'RECEIVABLE')) return false;

      const memo = t.memo.toLowerCase();
      const pattern = r.pattern.toLowerCase();

      if (r.type === 'EXACT') return memo === pattern;
      if (r.type === 'CONTAINS') return memo.includes(pattern);
      if (r.type === 'REGEX') {
        try {
          return new RegExp(pattern, 'i').test(memo);
        } catch (e) {
          return false;
        }
      }
      return false;
    });

    // 2. Score existing documents
    existing.forEach((e: any) => {
      if (e.status !== "Pendente") return;

      let score = 0;
      const reasons: string[] = [];

      // Amount match (Crucial - Weight: 70)
      if (Math.abs(e.amount) === Math.abs(t.amount)) {
        score += 70;
        reasons.push("Valor idêntico");
      } else if (Math.abs(Math.abs(e.amount) - Math.abs(t.amount)) < 0.05) {
        score += 40;
        reasons.push("Valor aproximado");
      }

      // Date match (Weight: 30)
      const eDate = new Date(e.due_date);
      const tDate = new Date(t.date);
      const diffDays = Math.abs(eDate.getTime() - tDate.getTime()) / (1000 * 60 * 60 * 24);

      if (diffDays <= 0.5) {
        score += 30;
        reasons.push("Data idêntica");
      } else if (diffDays <= 3) {
        score += 15;
        reasons.push("Data próxima");
      } else if (diffDays <= 7) {
        score += 5;
      }

      // Description match (Weight: 40)
      const similarity = getStringSimilarity(t.memo, e.description);
      if (similarity > 0.8) {
        score += 40;
        reasons.push("Descrição muito similar");
      } else if (similarity > 0.4) {
        score += 15;
        reasons.push("Descrição similar");
      }

      // Rule match boost (Weight: 50)
      if (matchingRule) {
        // If the rule points to the same supplier/client, it's a very strong match
        const ruleMatchesEntity = 
          (matchingRule.supplier_id && e.supplier_id === matchingRule.supplier_id) ||
          (matchingRule.client_id && e.client_id === matchingRule.client_id);

        if (ruleMatchesEntity) {
          score += 50;
          reasons.push("Regra de correspondência");
        } else if (getStringSimilarity(t.memo, matchingRule.pattern) > 0.8) {
          score += 20;
          reasons.push("Padrão de regra");
        }
      }

      if (score > (bestMatch?.score || 30)) {
        bestMatch = {
          match: e,
          score,
          reason: reasons.join(", "),
          isRuleMatch: !!matchingRule
        };
      }
    });

    return bestMatch;
  };

  const importMutation = useMutation({
    mutationFn: async (selectedIds: string[]) => {
      const toImport = transactions.filter(t => selectedIds.includes(t.id));

      for (const t of toImport) {
        const isExpense = t.type === "DEBIT";
        const endpoint = isExpense ? "accountsPayable" : "accountsReceivable";

        // Check manual match first
        const manualMatch = manualMatches[t.id];
        let match = manualMatch;

        if (!match) {
          const existing = isExpense ? payables : receivables;
          const result = findBestMatch(t, existing);
          if (result && result.score >= 70) {
            match = result.match;
          }
        }

        if (match) {
          // Update existing to Paid
          await api.put(endpoint, match.id, {
            status: "Pago",
            [isExpense ? "payment_date" : "receipt_date"]: t.date,
            bank_account_id: bankAccountId
          });
        } else {
          // Check for rule to pre-fill metadata
          const matchingRule = rules.find((r: any) => {
            if (r.target_type !== (isExpense ? 'PAYABLE' : 'RECEIVABLE')) return false;
            const memo = t.memo.toLowerCase();
            const pattern = r.pattern.toLowerCase();
            if (r.type === 'EXACT') return memo === pattern;
            if (r.type === 'CONTAINS') return memo.includes(pattern);
            return false;
          });

          // Create new entry
          await api.post(endpoint, {
            company_id: currentCompanyId,
            description: `OFX: ${t.memo}`,
            amount: Math.abs(t.amount),
            due_date: t.date,
            [isExpense ? "payment_date" : "receipt_date"]: t.date,
            status: "Pago",
            bank_account_id: bankAccountId,
            category_id: matchingRule?.category_id || null,
            supplier_id: matchingRule?.supplier_id || null,
            client_id: matchingRule?.client_id || null,
            created_at: new Date().toISOString()
          });
        }
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["accountsPayable"] });
      queryClient.invalidateQueries({ queryKey: ["accountsReceivable"] });
      queryClient.invalidateQueries({ queryKey: ["bankAccounts"] });
      toast.success("Importação e conciliação concluídas!");
      onClose();
    }
  });

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.name.toLowerCase().endsWith(".ofx")) {
      toast.error("Por favor, selecione um arquivo .ofx válido.");
      return;
    }

    setIsParsing(true);
    try {
      const text = await file.text();
      const data = await parse(text);

      // Robust navigation of the OFX structure
      const ofx = data.OFX;
      if (!ofx) throw new Error("Estrutura OFX inválida");

      const bankMsg = ofx.BANKMSGSRSV1 || ofx.CREDITCARDMSGSRSV1;
      if (!bankMsg) throw new Error("Mensagens bancárias não encontradas");

      const stmtTrnRs = bankMsg.STMTTRNRS || bankMsg.CCSTMTTRNRS;
      const stmtRs = Array.isArray(stmtTrnRs) ? stmtTrnRs[0].STMTRS || stmtTrnRs[0].CCSTMTRS : stmtTrnRs.STMTRS || stmtTrnRs.CCSTMTRS;
      const tranList = stmtRs.BANKTRANLIST?.STMTTRN || stmtRs.CCBANKTRANLIST?.STMTTRN;

      if (!tranList) {
        toast.info("Nenhuma transação encontrada no período deste extrato.");
        setTransactions([]);
        return;
      }

      const parsedTransactions: OFXTransaction[] = (Array.isArray(tranList) ? tranList : [tranList]).map((t: any) => {
        // OFX date format: YYYYMMDDHHMMSS
        const dateStr = t.DTPOSTED || "";
        const year = dateStr.substring(0, 4) || new Date().getFullYear().toString();
        const month = dateStr.substring(4, 6) || "01";
        const day = dateStr.substring(6, 8) || "01";
        const isoDate = `${year}-${month}-${day}T12:00:00Z`;

        return {
          id: t.FITID || Math.random().toString(36).substr(2, 9),
          type: t.TRNTYPE,
          date: isoDate,
          amount: parseFloat(t.TRNAMT),
          memo: t.MEMO || t.NAME || "Transação sem descrição",
          fitid: t.FITID
        };
      });

      setTransactions(parsedTransactions);
      setSelectedTransactions(new Set(parsedTransactions.map(t => t.id)));
      toast.success(`${parsedTransactions.length} transações encontradas.`);
    } catch (error) {
      console.error("Error parsing OFX:", error);
      toast.error("Erro ao processar o arquivo OFX. Verifique se o formato está correto.");
    } finally {
      setIsParsing(false);
    }
  };

  const toggleTransaction = (id: string) => {
    const newSelected = new Set(selectedTransactions);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedTransactions(newSelected);
  };

  const toggleAll = () => {
    if (selectedTransactions.size === transactions.length) {
      setSelectedTransactions(new Set());
    } else {
      setSelectedTransactions(new Set(transactions.map(t => t.id)));
    }
  };

  const handleManualMatch = (transactionId: string, match: any) => {
    setManualMatches(prev => ({ ...prev, [transactionId]: match }));
    setIsManualMatching(null);
    setIsSavingRule(transactionId); // Ask to save rule after manual match
    toast.success("Vínculo manual estabelecido!");
  };

  const saveRuleMutation = useMutation({
    mutationFn: async (transactionId: string) => {
      const t = transactions.find(tr => tr.id === transactionId);
      const m = manualMatches[transactionId];
      if (!t || !m) return;

      await api.post("reconciliation_rules", {
        company_id: currentCompanyId,
        pattern: t.memo,
        type: 'CONTAINS',
        target_type: t.type === "DEBIT" ? 'PAYABLE' : 'RECEIVABLE',
        category_id: m.category_id || null,
        supplier_id: m.supplier_id || null,
        client_id: m.client_id || null,
        auto_confirm: true,
        created_at: new Date().toISOString()
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["reconciliation_rules"] });
      toast.success("Regra de conciliação salva!");
      setIsSavingRule(null);
    }
  });

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={onClose} />
      <div className="relative bg-white w-full max-w-5xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-white sticky top-0 z-10">
          <div>
            <h2 className="text-xl font-bold">Importar Extrato OFX</h2>
            <p className="text-sm text-gray-500">Conciliação para: <span className="font-bold text-blue-600">{bankAccountName}</span></p>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6">
          {transactions.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-6 border-2 border-dashed border-gray-100 rounded-3xl">
              <div className="p-6 bg-blue-50 text-blue-600 rounded-full">
                <Upload size={48} />
              </div>
              <div className="text-center space-y-2">
                <h3 className="text-lg font-bold text-gray-900">Selecione o arquivo .ofx</h3>
                <p className="text-gray-500 max-w-xs mx-auto">
                  Arraste o arquivo aqui ou clique no botão abaixo para selecionar o extrato do seu banco.
                </p>
              </div>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                accept=".ofx" 
                className="hidden" 
              />
              <button 
                onClick={() => fileInputRef.current?.click()}
                disabled={isParsing}
                className="px-8 py-3 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 disabled:opacity-50"
              >
                {isParsing ? "Processando..." : "Selecionar Arquivo"}
              </button>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="flex items-center justify-between bg-gray-50 p-4 rounded-2xl border border-gray-100">
                <div className="flex items-center gap-4">
                  <button 
                    onClick={toggleAll}
                    className="flex items-center gap-2 text-sm font-bold text-blue-600 hover:text-blue-700"
                  >
                    {selectedTransactions.size === transactions.length ? "Desmarcar Todos" : "Selecionar Todos"}
                  </button>
                  <span className="text-sm text-gray-500">
                    {selectedTransactions.size} de {transactions.length} selecionados
                  </span>
                </div>
                <button 
                  onClick={() => {
                    setTransactions([]);
                    setManualMatches({});
                  }}
                  className="text-sm font-bold text-red-600 hover:text-red-700"
                >
                  Trocar Arquivo
                </button>
              </div>

              <div className="space-y-3">
                {transactions.map((t) => {
                  const isExpense = t.type === "DEBIT";
                  const existing = isExpense ? payables : receivables;

                  // Check manual match first
                  const manualMatch = manualMatches[t.id];
                  let matchResult = manualMatch ? { match: manualMatch, score: 100, reason: "Vínculo Manual" } : null;

                  if (!matchResult) {
                    matchResult = findBestMatch(t, existing);
                  }

                  const match = matchResult?.match;
                  const score = matchResult?.score || 0;

                  return (
                    <div 
                      key={t.id} 
                      className={`p-4 rounded-2xl border transition-all flex items-center gap-4 ${
                        selectedTransactions.has(t.id) 
                          ? "border-blue-200 bg-blue-50/30" 
                          : "border-gray-100 hover:border-gray-200"
                      }`}
                    >
                      <div 
                        onClick={() => toggleTransaction(t.id)}
                        className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors cursor-pointer ${
                          selectedTransactions.has(t.id) 
                            ? "bg-blue-600 border-blue-600 text-white" 
                            : "border-gray-200"
                        }`}
                      >
                        {selectedTransactions.has(t.id) && <Check size={14} />}
                      </div>

                      <div className={`p-3 rounded-xl ${isExpense ? "bg-red-50 text-red-600" : "bg-green-50 text-green-600"}`}>
                        {isExpense ? <ArrowDownLeft size={20} /> : <ArrowUpRight size={20} />}
                      </div>

                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <h4 className="font-bold text-gray-900 truncate">{t.memo}</h4>
                          {matchResult && (
                            <span className={`flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${
                              manualMatch 
                                ? "bg-blue-100 text-blue-700" 
                                : score >= 80 
                                  ? "bg-green-100 text-green-700" 
                                  : "bg-yellow-100 text-yellow-700"
                            }`}>
                              <CheckCircle2 size={10} /> 
                              {manualMatch ? "Vínculo Manual" : score >= 80 ? "Conciliação Automática" : "Sugestão"}
                            </span>
                          )}
                        </div>
                        <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                          <span>{formatBR(t.date)}</span>
                          <span>•</span>
                          <span>ID: {t.fitid}</span>
                          {matchResult && !manualMatch && (
                            <>
                              <span>•</span>
                              <span className="text-blue-600 font-medium">{matchResult.reason}</span>
                            </>
                          )}
                        </div>
                      </div>

                      <div className="text-right flex items-center gap-6">
                        <div className="min-w-[120px]">
                          <p className={`text-lg font-bold ${isExpense ? "text-red-600" : "text-green-600"}`}>
                            {isExpense ? "-" : "+"} R$ {Math.abs(t.amount).toLocaleString()}
                          </p>
                          {match && (
                            <p className="text-[10px] text-gray-400 italic truncate max-w-[150px]">
                              {match.description}
                            </p>
                          )}
                        </div>

                        <div className="flex flex-col gap-1">
                          {match ? (
                            <button 
                              onClick={() => setManualMatches(prev => {
                                const next = { ...prev };
                                delete next[t.id];
                                return next;
                              })}
                              className="text-[10px] font-bold text-red-500 hover:underline"
                            >
                              Remover Vínculo
                            </button>
                          ) : (
                            <button 
                              onClick={() => setIsManualMatching(t.id)}
                              className="text-[10px] font-bold text-blue-600 hover:underline flex items-center gap-1"
                            >
                              <ArrowRightLeft size={10} /> Vincular Manual
                            </button>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        <div className="p-6 border-t border-gray-100 bg-gray-50 flex justify-end gap-3 sticky bottom-0 z-10">
          <button 
            onClick={onClose}
            className="px-6 py-2 text-gray-500 font-bold hover:text-gray-700 transition-colors"
          >
            Cancelar
          </button>
          <button 
            onClick={() => importMutation.mutate(Array.from(selectedTransactions))}
            disabled={selectedTransactions.size === 0 || importMutation.isPending}
            className="px-8 py-2 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 disabled:opacity-50 flex items-center gap-2"
          >
            {importMutation.isPending ? (
              <>Processando...</>
            ) : (
              <>
                <CheckCircle2 size={18} />
                Confirmar Conciliação ({selectedTransactions.size})
              </>
            )}
          </button>
        </div>
      </div>

      {/* Manual Matching Modal */}
      {isManualMatching && (
        <div className="fixed inset-0 z-[80] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsManualMatching(null)} />
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[80vh]">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-white sticky top-0 z-10">
              <h3 className="text-lg font-bold">Vincular Lançamento Manualmente</h3>
              <button onClick={() => setIsManualMatching(null)} className="text-gray-400 hover:text-gray-600">✕</button>
            </div>
            <div className="p-6 overflow-y-auto space-y-4">
              <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100">
                <p className="text-xs font-bold text-blue-600 uppercase mb-1">Transação do Extrato</p>
                <div className="flex justify-between items-center">
                  <p className="font-bold text-gray-900">{transactions.find(t => t.id === isManualMatching)?.memo}</p>
                  <p className="font-bold text-blue-600">R$ {Math.abs(transactions.find(t => t.id === isManualMatching)?.amount || 0).toLocaleString()}</p>
                </div>
              </div>

              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-700">Selecione o lançamento no sistema:</p>
                <div className="divide-y divide-gray-50 border border-gray-100 rounded-2xl overflow-hidden">
                  {(transactions.find(t => t.id === isManualMatching)?.type === "DEBIT" ? payables : receivables)
                    .filter((e: any) => e.status === "Pendente")
                    .map((e: any) => (
                      <button
                        key={e.id}
                        onClick={() => handleManualMatch(isManualMatching, e)}
                        className="w-full p-4 text-left hover:bg-gray-50 transition-colors flex justify-between items-center group"
                      >
                        <div>
                          <p className="font-bold text-gray-900 group-hover:text-blue-600 transition-colors">{e.description}</p>
                          <p className="text-xs text-gray-500">Vencimento: {formatBR(e.due_date)}</p>
                        </div>
                        <div className="text-right">
                          <p className="font-bold text-gray-900">R$ {e.amount?.toLocaleString()}</p>
                          <p className="text-[10px] text-blue-600 font-bold uppercase">Selecionar</p>
                        </div>
                      </button>
                    ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Save Rule Modal */}
      {isSavingRule && (
        <div className="fixed inset-0 z-[90] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsSavingRule(null)} />
          <div className="relative bg-white w-full max-w-md rounded-3xl shadow-2xl p-8 text-center space-y-6">
            <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto">
              <ArrowRightLeft size={40} />
            </div>
            <div className="space-y-2">
              <h3 className="text-xl font-bold">Criar Regra de Conciliação?</h3>
              <p className="text-gray-500">
                Deseja que o sistema aprenda este vínculo? Transações futuras com a descrição 
                <span className="font-bold text-gray-900"> "{transactions.find(t => t.id === isSavingRule)?.memo}"</span> serão 
                conciliadas automaticamente.
              </p>
            </div>
            <div className="flex gap-3">
              <button 
                onClick={() => setIsSavingRule(null)}
                className="flex-1 py-3 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl transition-colors"
              >
                Agora não
              </button>
              <button 
                onClick={() => saveRuleMutation.mutate(isSavingRule)}
                disabled={saveRuleMutation.isPending}
                className="flex-1 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
              >
                {saveRuleMutation.isPending ? "Salvando..." : "Sim, Criar Regra"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "motion/react";
import { 
  Search, 
  X, 
  Package, 
  Users, 
  ShoppingCart, 
  Command,
  ChevronRight,
  Loader2,
  ArrowRight
} from "lucide-react";
import { api } from "../lib/api";
import { useAuth } from "../lib/auth";
import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

interface SearchResult {
  id: string;
  title: string;
  subtitle?: string;
  type: 'product' | 'client' | 'sale';
  path: string;
}

export default function GlobalSearch() {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState("");
  const [results, setResults] = useState<SearchResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const navigate = useNavigate();
  const { user } = useAuth();
  const inputRef = useRef<HTMLInputElement>(null);
  const currentCompanyId = api.getCompanyId();

  // Keyboard shortcut: Ctrl+K or Cmd+K
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === "k") {
        e.preventDefault();
        setIsOpen(true);
      }
      if (e.key === "Escape") {
        setIsOpen(false);
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, []);

  // Focus input when modal opens
  useEffect(() => {
    if (isOpen) {
      setTimeout(() => {
        inputRef.current?.focus();
        setSelectedIndex(0);
      }, 100);
    }
  }, [isOpen]);

  // Search logic
  useEffect(() => {
    if (query.length < 2) {
      setTimeout(() => setResults([]), 0);
      return;
    }

    const delayDebounceFn = setTimeout(async () => {
      setIsLoading(true);
      try {
        const [products, clients, sales] = await Promise.all([
          api.get("products", { company_id: currentCompanyId }),
          api.get("clients", { company_id: currentCompanyId }),
          api.get("sales", { company_id: currentCompanyId })
        ]);

        const searchLower = query.toLowerCase();

        const productResults: SearchResult[] = products
          .filter((p: any) => p.name?.toLowerCase().includes(searchLower))
          .slice(0, 3)
          .map((p: any) => ({
            id: p.id,
            title: p.name,
            subtitle: `Estoque: ${p.stock_quantity} | R$ ${p.sale_price}`,
            type: 'product',
            path: '/Produtos'
          }));

        const clientResults: SearchResult[] = clients
          .filter((c: any) => c.name?.toLowerCase().includes(searchLower) || c.document?.includes(query))
          .slice(0, 3)
          .map((c: any) => ({
            id: c.id,
            title: c.name,
            subtitle: c.email || c.phone,
            type: 'client',
            path: '/Clientes'
          }));

        const saleResults: SearchResult[] = sales
          .filter((s: any) => 
            s.id.toLowerCase().includes(searchLower) || 
            s.client_name?.toLowerCase().includes(searchLower)
          )
          .slice(0, 3)
          .map((s: any) => ({
            id: s.id,
            title: `Venda #${s.id.substring(0, 8).toUpperCase()}`,
            subtitle: `${s.client_name} | R$ ${s.total}`,
            type: 'sale',
            path: '/HistoricoVendas'
          }));

        setResults([...productResults, ...clientResults, ...saleResults]);
      } catch (error) {
        console.error("Search error:", error);
      } finally {
        setIsLoading(false);
      }
    }, 300);

    return () => clearTimeout(delayDebounceFn);
  }, [query, currentCompanyId]);

  const handleSelect = (result: SearchResult) => {
    navigate(result.path);
    setIsOpen(false);
    setQuery("");
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "ArrowDown") {
      setSelectedIndex(prev => (prev + 1) % results.length);
    } else if (e.key === "ArrowUp") {
      setSelectedIndex(prev => (prev - 1 + results.length) % results.length);
    } else if (e.key === "Enter" && results[selectedIndex]) {
      handleSelect(results[selectedIndex]);
    }
  };

  const getTypeIcon = (type: SearchResult['type']) => {
    switch (type) {
      case 'product': return <Package size={18} className="text-blue-500" />;
      case 'client': return <Users size={18} className="text-green-500" />;
      case 'sale': return <ShoppingCart size={18} className="text-purple-500" />;
    }
  };

  const getTypeName = (type: SearchResult['type']) => {
    switch (type) {
      case 'product': return 'Produto';
      case 'client': return 'Cliente';
      case 'sale': return 'Venda';
    }
  };

  return (
    <>
      {/* Search Trigger Button */}
      <button
        onClick={() => setIsOpen(true)}
        className="flex items-center gap-3 px-4 py-2 bg-gray-50 border border-gray-100 rounded-xl text-gray-400 hover:bg-gray-100 hover:text-gray-600 transition-all w-full max-w-md group"
      >
        <Search size={18} className="group-hover:text-blue-500 transition-colors" />
        <span className="text-sm flex-1 text-left">Buscar produtos, clientes...</span>
        <div className="hidden sm:flex items-center gap-1 px-1.5 py-0.5 bg-white border border-gray-200 rounded text-[10px] font-bold text-gray-400">
          <Command size={10} /> K
        </div>
      </button>

      {/* Search Modal */}
      <AnimatePresence>
        {isOpen && (
          <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[10vh] px-4">
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="absolute inset-0 bg-black/40 backdrop-blur-sm"
              onClick={() => setIsOpen(false)}
            />

            <motion.div
              initial={{ opacity: 0, scale: 0.95, y: -20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95, y: -20 }}
              className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden border border-gray-100"
            >
              {/* Search Input */}
              <div className="p-6 border-b border-gray-100 flex items-center gap-4">
                <Search size={24} className={cn("transition-colors", isLoading ? "text-blue-500" : "text-gray-400")} />
                <input
                  ref={inputRef}
                  type="text"
                  placeholder="O que você está procurando?"
                  className="flex-1 bg-transparent border-none outline-none text-lg text-gray-900 placeholder:text-gray-400"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onKeyDown={handleKeyDown}
                />
                {isLoading ? (
                  <Loader2 size={20} className="animate-spin text-blue-500" />
                ) : (
                  <button onClick={() => setIsOpen(false)} className="p-1 hover:bg-gray-100 rounded-full text-gray-400 transition-colors">
                    <X size={20} />
                  </button>
                )}
              </div>

              {/* Results Area */}
              <div className="max-h-[60vh] overflow-y-auto p-2">
                {query.length < 2 ? (
                  <div className="p-12 text-center space-y-4">
                    <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mx-auto text-gray-300">
                      <Search size={32} />
                    </div>
                    <div>
                      <p className="text-gray-900 font-medium">Busca Inteligente</p>
                      <p className="text-sm text-gray-500">Digite pelo menos 2 caracteres para pesquisar em todo o sistema.</p>
                    </div>
                    <div className="flex items-center justify-center gap-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                      <span className="flex items-center gap-1"><Package size={12} /> Produtos</span>
                      <span className="flex items-center gap-1"><Users size={12} /> Clientes</span>
                      <span className="flex items-center gap-1"><ShoppingCart size={12} /> Vendas</span>
                    </div>
                  </div>
                ) : results.length > 0 ? (
                  <div className="space-y-1">
                    {results.map((result, index) => (
                      <button
                        key={`${result.type}-${result.id}`}
                        onClick={() => handleSelect(result)}
                        onMouseEnter={() => setSelectedIndex(index)}
                        className={cn(
                          "w-full flex items-center gap-4 p-4 rounded-2xl transition-all text-left group",
                          selectedIndex === index ? "bg-blue-50" : "hover:bg-gray-50"
                        )}
                      >
                        <div className={cn(
                          "w-12 h-12 rounded-xl flex items-center justify-center transition-colors",
                          selectedIndex === index ? "bg-white text-blue-600 shadow-sm" : "bg-gray-50 text-gray-400"
                        )}>
                          {getTypeIcon(result.type)}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            <span className="text-sm font-bold text-gray-900 truncate">{result.title}</span>
                            <span className="text-[10px] font-bold px-1.5 py-0.5 bg-gray-100 text-gray-500 rounded uppercase tracking-tighter">
                              {getTypeName(result.type)}
                            </span>
                          </div>
                          <p className="text-xs text-gray-500 truncate">{result.subtitle}</p>
                        </div>
                        <div className={cn(
                          "transition-all",
                          selectedIndex === index ? "translate-x-0 opacity-100" : "-translate-x-2 opacity-0"
                        )}>
                          <ArrowRight size={18} className="text-blue-600" />
                        </div>
                      </button>
                    ))}
                  </div>
                ) : !isLoading && (
                  <div className="p-12 text-center space-y-4">
                    <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto text-red-200">
                      <X size={32} />
                    </div>
                    <div>
                      <p className="text-gray-900 font-medium">Nenhum resultado encontrado</p>
                      <p className="text-sm text-gray-500">Não encontramos nada para "{query}". Tente outros termos.</p>
                    </div>
                  </div>
                )}
              </div>

              {/* Footer */}
              <div className="p-4 bg-gray-50 border-t border-gray-100 flex items-center justify-between text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                <div className="flex items-center gap-4">
                  <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white border border-gray-200 rounded shadow-sm text-gray-500">↵</kbd> Selecionar</span>
                  <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white border border-gray-200 rounded shadow-sm text-gray-500">↑↓</kbd> Navegar</span>
                </div>
                <div className="flex items-center gap-1">
                  <kbd className="px-1.5 py-0.5 bg-white border border-gray-200 rounded shadow-sm text-gray-500">ESC</kbd> Fechar
                </div>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </>
  );
}

import React, { useState, useEffect, useRef } from "react";
import { api } from "../lib/api";
import { 
  Printer, 
  Search, 
  X, 
  Settings, 
  CheckSquare, 
  Square,
  Plus,
  Minus,
  Download
} from "lucide-react";
import { jsPDF } from "jspdf";
import JsBarcode from "jsbarcode";
import { toast } from "sonner";

interface LabelPrinterProps {
  isOpen: boolean;
  onClose: () => void;
  products: any[];
}

interface LabelLayout {
  name: string;
  rows: number;
  cols: number;
  labelWidth: number; // mm
  labelHeight: number; // mm
  marginTop: number; // mm
  marginLeft: number; // mm
  colGap: number; // mm
  rowGap: number; // mm
}

const LAYOUT_PRESETS: LabelLayout[] = [
  {
    name: "Pimenta 6180 (3x7)",
    rows: 7,
    cols: 3,
    labelWidth: 63.5,
    labelHeight: 38.1,
    marginTop: 15.1,
    marginLeft: 7.2,
    colGap: 2.5,
    rowGap: 0
  },
  {
    name: "Avery 5160 (3x10)",
    rows: 10,
    cols: 3,
    labelWidth: 66.6,
    labelHeight: 25.4,
    marginTop: 12.7,
    marginLeft: 4.7,
    colGap: 3.1,
    rowGap: 0
  },
  {
    name: "Etiqueta Única (80x40)",
    rows: 1,
    cols: 1,
    labelWidth: 80,
    labelHeight: 40,
    marginTop: 0,
    marginLeft: 0,
    colGap: 0,
    rowGap: 0
  }
];

export default function LabelPrinter({ isOpen, onClose, products }: LabelPrinterProps) {
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedItems, setSelectedItems] = useState<Record<string, number>>({});
  const [layout, setLayout] = useState<LabelLayout>(LAYOUT_PRESETS[0]);
  const [showSettings, setShowSettings] = useState(false);
  const barcodeRef = useRef<HTMLCanvasElement>(null);

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.sku?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const toggleItem = (productId: string) => {
    setSelectedItems(prev => {
      const newItems = { ...prev };
      if (newItems[productId]) {
        delete newItems[productId];
      } else {
        newItems[productId] = 1;
      }
      return newItems;
    });
  };

  const updateQuantity = (productId: string, delta: number) => {
    setSelectedItems(prev => {
      const current = prev[productId] || 0;
      const next = Math.max(1, current + delta);
      return { ...prev, [productId]: next };
    });
  };

  const generateBarcodeBase64 = (value: string): string | null => {
    if (!barcodeRef.current) return null;
    try {
      JsBarcode(barcodeRef.current, value, {
        format: "EAN13",
        width: 2,
        height: 40,
        displayValue: true,
        fontSize: 14,
        margin: 0
      });
      return barcodeRef.current.toDataURL("image/png");
    } catch (e) {
      // Fallback to CODE128 if EAN13 fails (e.g. invalid checksum or length)
      try {
        JsBarcode(barcodeRef.current, value, {
          format: "CODE128",
          width: 2,
          height: 40,
          displayValue: true,
          fontSize: 14,
          margin: 0
        });
        return barcodeRef.current.toDataURL("image/png");
      } catch (err) {
        console.error("Error generating barcode:", err);
        return null;
      }
    }
  };

  const handleGeneratePDF = async () => {
    const selectedProductIds = Object.keys(selectedItems);
    if (selectedProductIds.length === 0) {
      toast.error("Selecione pelo menos um produto.");
      return;
    }

    const doc = new jsPDF({
      orientation: "portrait",
      unit: "mm",
      format: "a4"
    });

    let currentX = layout.marginLeft;
    let currentY = layout.marginTop;
    let currentCol = 0;
    let currentRow = 0;

    const itemsToPrint: any[] = [];
    selectedProductIds.forEach(id => {
      const product = products.find(p => p.id === id);
      const qty = selectedItems[id];
      for (let i = 0; i < qty; i++) {
        itemsToPrint.push(product);
      }
    });

    toast.info(`Gerando ${itemsToPrint.length} etiquetas...`);

    for (let i = 0; i < itemsToPrint.length; i++) {
      const product = itemsToPrint[i];

      // Draw label content
      const centerX = currentX + layout.labelWidth / 2;

      // Product Name
      doc.setFontSize(8);
      doc.setFont("helvetica", "bold");
      const nameLines = doc.splitTextToSize(product.name, layout.labelWidth - 4);
      doc.text(nameLines[0], centerX, currentY + 5, { align: "center" });

      // Price
      doc.setFontSize(10);
      doc.setTextColor(0, 0, 0);
      const priceText = `R$ ${product.price?.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;
      doc.text(priceText, centerX, currentY + 12, { align: "center" });

      // Barcode
      const barcodeValue = product.sku || product.id.substring(0, 12).padStart(12, '0');
      const barcodeImg = generateBarcodeBase64(barcodeValue);
      if (barcodeImg) {
        // Calculate barcode size to fit
        const imgW = layout.labelWidth - 10;
        const imgH = 15;
        doc.addImage(barcodeImg, "PNG", centerX - imgW / 2, currentY + 15, imgW, imgH);
      }

      // Update positions
      currentCol++;
      if (currentCol >= layout.cols) {
        currentCol = 0;
        currentRow++;
        currentX = layout.marginLeft;
        currentY += layout.labelHeight + layout.rowGap;
      } else {
        currentX += layout.labelWidth + layout.colGap;
      }

      // Check for new page
      if (currentRow >= layout.rows && i < itemsToPrint.length - 1) {
        doc.addPage();
        currentRow = 0;
        currentCol = 0;
        currentX = layout.marginLeft;
        currentY = layout.marginTop;
      }
    }

    doc.save("etiquetas-produtos.pdf");
    toast.success("PDF gerado com sucesso!");
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-white sticky top-0 z-10">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-blue-600 text-white rounded-xl">
              <Printer size={24} />
            </div>
            <div>
              <h2 className="text-xl font-bold text-gray-900">Impressão de Etiquetas</h2>
              <p className="text-xs text-gray-500">Selecione os produtos e configure o layout.</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={() => setShowSettings(!showSettings)}
              className={`p-2 rounded-xl transition-colors ${showSettings ? "bg-blue-50 text-blue-600" : "text-gray-400 hover:bg-gray-50"}`}
            >
              <Settings size={20} />
            </button>
            <button onClick={onClose} className="p-2 text-gray-400 hover:text-gray-600">
              <X size={24} />
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
          {/* Product Selection */}
          <div className="flex-1 flex flex-col border-r border-gray-100">
            <div className="p-4 border-b border-gray-50">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Buscar produtos..." 
                  className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl outline-none focus:ring-2 focus:ring-blue-500"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-2">
              {filteredProducts.map(p => {
                const isSelected = !!selectedItems[p.id];
                return (
                  <div 
                    key={p.id} 
                    className={`flex items-center justify-between p-3 rounded-2xl border transition-all ${
                      isSelected ? "border-blue-200 bg-blue-50/50" : "border-gray-100 hover:border-gray-200"
                    }`}
                  >
                    <div className="flex items-center gap-3 flex-1 cursor-pointer" onClick={() => toggleItem(p.id)}>
                      {isSelected ? (
                        <CheckSquare className="text-blue-600" size={20} />
                      ) : (
                        <Square className="text-gray-300" size={20} />
                      )}
                      <div>
                        <p className="text-sm font-bold text-gray-900">{p.name}</p>
                        <p className="text-[10px] text-gray-500 font-mono">SKU: {p.sku || p.id.substring(0, 8)}</p>
                      </div>
                    </div>

                    {isSelected && (
                      <div className="flex items-center gap-3 bg-white p-1 rounded-lg border border-blue-100">
                        <button 
                          onClick={() => updateQuantity(p.id, -1)}
                          className="p-1 text-gray-400 hover:text-blue-600"
                        >
                          <Minus size={14} />
                        </button>
                        <span className="text-xs font-bold w-6 text-center">{selectedItems[p.id]}</span>
                        <button 
                          onClick={() => updateQuantity(p.id, 1)}
                          className="p-1 text-gray-400 hover:text-blue-600"
                        >
                          <Plus size={14} />
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Settings / Preview */}
          <div className={`w-full md:w-80 bg-gray-50 p-6 overflow-y-auto transition-all ${showSettings ? "block" : "hidden md:block"}`}>
            <h3 className="font-bold text-gray-900 mb-6 flex items-center gap-2">
              <Settings size={18} className="text-blue-600" />
              Configurações do Layout
            </h3>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-gray-400 uppercase">Preset de Layout</label>
                <select 
                  className="w-full p-2 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                  value={layout.name}
                  onChange={(e) => {
                    const preset = LAYOUT_PRESETS.find(p => p.name === e.target.value);
                    if (preset) setLayout(preset);
                  }}
                >
                  {LAYOUT_PRESETS.map(p => (
                    <option key={p.name} value={p.name}>{p.name}</option>
                  ))}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase">Colunas</label>
                  <input 
                    type="number" 
                    className="w-full p-2 bg-white border border-gray-200 rounded-xl outline-none text-sm"
                    value={layout.cols}
                    onChange={(e) => setLayout({...layout, cols: parseInt(e.target.value) || 1})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase">Linhas</label>
                  <input 
                    type="number" 
                    className="w-full p-2 bg-white border border-gray-200 rounded-xl outline-none text-sm"
                    value={layout.rows}
                    onChange={(e) => setLayout({...layout, rows: parseInt(e.target.value) || 1})}
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase">Largura (mm)</label>
                  <input 
                    type="number" 
                    className="w-full p-2 bg-white border border-gray-200 rounded-xl outline-none text-sm"
                    value={layout.labelWidth}
                    onChange={(e) => setLayout({...layout, labelWidth: parseFloat(e.target.value) || 1})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase">Altura (mm)</label>
                  <input 
                    type="number" 
                    className="w-full p-2 bg-white border border-gray-200 rounded-xl outline-none text-sm"
                    value={layout.labelHeight}
                    onChange={(e) => setLayout({...layout, labelHeight: parseFloat(e.target.value) || 1})}
                  />
                </div>
              </div>

              <div className="pt-4 border-t border-gray-200">
                <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100">
                  <p className="text-[10px] text-blue-800 font-medium">
                    Resumo: {layout.cols * layout.rows} etiquetas por página A4.
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-gray-100 bg-white flex justify-between items-center">
          <div className="text-sm text-gray-500">
            <span className="font-bold text-gray-900">{Object.keys(selectedItems).length}</span> produtos selecionados
          </div>
          <div className="flex gap-3">
            <button 
              onClick={onClose}
              className="px-6 py-2 text-gray-500 font-bold hover:bg-gray-50 rounded-xl transition-colors"
            >
              Cancelar
            </button>
            <button 
              onClick={handleGeneratePDF}
              className="flex items-center gap-2 px-8 py-2 bg-blue-600 text-white rounded-xl font-bold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all"
            >
              <Download size={20} />
              Gerar PDF
            </button>
          </div>
        </div>
      </div>

      {/* Hidden canvas for barcode generation */}
      <canvas ref={barcodeRef} className="hidden" />
    </div>
  );
}

