import { auth, db } from "./firebase";
import { collection, doc, getDoc, getDocs, setDoc, updateDoc, deleteDoc, query, where, serverTimestamp, orderBy, limit, OrderByDirection, onSnapshot, QueryConstraint, Query, DocumentData, QuerySnapshot, QueryDocumentSnapshot } from "firebase/firestore";
import { User, AuditLog } from "../types";

let currentCompanyId: string | null = null;
let isSystemAdminStatus = false;
let currentUserData: User | null = null;

const cleanObject = (obj: unknown): Record<string, unknown> | unknown => {
  if (!obj || typeof obj !== 'object') return obj;
  const newObj = { ...(obj as Record<string, unknown>) };
  Object.keys(newObj).forEach(key => {
    if (newObj[key] === undefined) {
      delete newObj[key];
    }
  });
  return newObj;
};

export const api = {
  setCompanyId: (id: string | null) => {
    currentCompanyId = id;
  },
  getCompanyId: () => currentCompanyId,
  setIsSystemAdmin: (isMaster: boolean) => {
    isSystemAdminStatus = isMaster;
  },
  setSessionId: (id: string | null) => {
    // No longer used
  },
  getCurrentUser: () => currentUserData,
  findUserByEmail: async (email: string): Promise<User | null> => {
    const q = query(collection(db, "users"), where("email", "==", email));
    const snapshot = await getDocs(q);
    if (snapshot.empty) return null;
    return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as User;
  },
  get: async <T = any>(entityPath: string, paramsOrId?: Record<string, unknown> | string): Promise<any> => {
    if (entityPath === "me") {
      const user = auth.currentUser;
      if (!user) throw new Error("Not authenticated");

      const isMasterEmail = user.email?.toLowerCase() === "sys.powercontrol@gmail.com";

      try {
        const userDoc = await getDoc(doc(db, "users", user.uid));
        if (userDoc.exists()) {
          const userData = userDoc.data();
          currentUserData = { id: user.uid, ...userData } as User;
          if (isMasterEmail && userData.role !== "master") {
            await updateDoc(doc(db, "users", user.uid), { role: "master" });
            userData.role = "master";
            currentUserData.role = "master";
          }
          return currentUserData as T;
        } else {
          const newUser = {
            email: user.email || '',
            full_name: user.email?.split("@")[0] || "Usuário",
            role: isMasterEmail ? "master" : "user",
            company_id: null,
            created_at: serverTimestamp(),
            is_active: true,
          };
          await setDoc(doc(db, "users", user.uid), newUser);
          currentUserData = { id: user.uid, ...newUser } as User;
          return currentUserData as T;
        }
      } catch (error: unknown) {
        if (error instanceof Error) {
          console.error("Firestore error in get('me'):", error.message);
        }
        // Fallback
        currentUserData = {
          id: user.uid,
          email: user.email || '',
          full_name: user.email?.split("@")[0] || "Usuário",
          role: isMasterEmail ? "master" : "user",
          company_id: null,
          is_active: true,
          created_at: new Date().toISOString()
        } as User;
        return currentUserData as T;
      }
    }

    const pathSegments = entityPath.split("/");
    const isDocumentPath = pathSegments.length % 2 === 0;

    if (typeof paramsOrId === "string" || isDocumentPath) {
      let docRef;
      if (typeof paramsOrId === "string") {
        docRef = doc(db, entityPath, paramsOrId);
      } else {
        docRef = doc(db, entityPath);
      }

      const docSnap = await getDoc(docRef);
      if (!docSnap.exists()) throw new Error("Not found");
      const data = docSnap.data();
      return { id: docSnap.id, ...(typeof data === 'object' && data !== null ? data : {}) } as T;
    } else {
      let q: Query<DocumentData> = collection(db, entityPath);
      const conditions: QueryConstraint[] = [];

      if (paramsOrId && typeof paramsOrId === "object") {
        Object.keys(paramsOrId).forEach(key => {
          if (paramsOrId[key] !== undefined && key !== "_all" && key !== "_orderBy" && key !== "_orderDir" && key !== "_limit") {
            conditions.push(where(key, "==", paramsOrId[key]));
          }
        });
      }

      const baseEntity = pathSegments[0];
      const isCompanyEntity = baseEntity === "companies";

      const requiresIsolation = !isSystemAdminStatus && !isCompanyEntity;

      if (requiresIsolation) {
        if (!currentCompanyId) {
          console.warn(`Race condition avoided: Cannot query ${entityPath} without company_id.`);
          return [] as T[];
        }
        conditions.push(where("company_id", "==", currentCompanyId));
      } else if (isSystemAdminStatus && currentCompanyId && !(paramsOrId && paramsOrId._all) && !isCompanyEntity) {
        conditions.push(where("company_id", "==", currentCompanyId));
      }

      const queryConstraints: QueryConstraint[] = [...conditions];

      if (paramsOrId && typeof paramsOrId === "object") {
        if (paramsOrId._orderBy) {
          queryConstraints.push(orderBy(paramsOrId._orderBy as string, (paramsOrId._orderDir as OrderByDirection) || "asc"));
        }
        if (paramsOrId._limit) {
          queryConstraints.push(limit(paramsOrId._limit as number));
        }
      }

      if (queryConstraints.length > 0) {
        q = query(q, ...queryConstraints);
      }

      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => {
        const data = doc.data();
        return { id: doc.id, ...(typeof data === 'object' && data !== null ? data : {}) };
      }) as T[];
    }
  },
  post: async <T = any>(entity: string, data: Partial<T> | Record<string, unknown>): Promise<T> => {
    const payload = cleanObject({ ...data }) as Record<string, unknown>;

    if (!payload.company_id && currentCompanyId && entity !== "companies" && entity !== "users") {
      payload.company_id = currentCompanyId;
    }

    if (!payload.created_at) {
      payload.created_at = serverTimestamp();
    }

    const newDocRef = doc(collection(db, entity));
    await setDoc(newDocRef, payload);
    return { id: newDocRef.id, ...payload } as T;
  },
  put: async <T = any>(entity: string, id: string, data: Partial<T> | Record<string, unknown>): Promise<T> => {
    const docRef = doc(db, entity, id);
    const payload = cleanObject(data) as Record<string, unknown>;
    await updateDoc(docRef, payload);
    return { id, ...payload } as T;
  },
  delete: async (entity: string, id: string): Promise<boolean> => {
    const docRef = doc(db, entity, id);
    await deleteDoc(docRef);
    return true;
  },
  subscribe: <T = any>(entityPath: string, params: Record<string, unknown> | null, callback: (data: T[]) => void) => {
    let q: Query<DocumentData> = collection(db, entityPath);
    const conditions: QueryConstraint[] = [];

    if (params && typeof params === "object") {
      Object.keys(params).forEach(key => {
        if (params[key] !== undefined && key !== "_orderBy" && key !== "_orderDir" && key !== "_limit" && key !== "_all") {
          conditions.push(where(key, "==", params[key]));
        }
      });
    }

    const pathSegments = entityPath.split("/");
    const baseEntity = pathSegments[0];
    const isCompanyEntity = baseEntity === "companies";

    const requiresIsolation = !isSystemAdminStatus && !isCompanyEntity;

    if (requiresIsolation) {
      if (!currentCompanyId) {
        console.warn(`Race condition avoided in subscribe: Cannot query ${entityPath} without company_id.`);
        return () => {}; // return empty unsubscribe function
      }
      conditions.push(where("company_id", "==", currentCompanyId));
    } else if (isSystemAdminStatus && currentCompanyId && !(params && params._all) && !isCompanyEntity) {
      conditions.push(where("company_id", "==", currentCompanyId));
    }

    const queryConstraints: QueryConstraint[] = [...conditions];
    if (params?._orderBy) {
      queryConstraints.push(orderBy(params._orderBy as string, (params._orderDir as OrderByDirection) || "asc"));
    }
    if (params?._limit) {
      queryConstraints.push(limit(params._limit as number));
    }

    if (queryConstraints.length > 0) {
      q = query(q, ...queryConstraints);
    }

    return onSnapshot(q, (snapshot: QuerySnapshot<DocumentData>) => {
      const data = snapshot.docs.map((doc: QueryDocumentSnapshot<DocumentData>) => ({ id: doc.id, ...doc.data() }));
      callback(data as T[]);
    });
  },
  log: async (data: Partial<AuditLog>, userContext?: User): Promise<void> => {
    const user = userContext ? userContext : auth.currentUser;
    if (!user) return;

    const logData = {
      ...data,
      user_id: userContext?.id || (user as any).uid || (user as any).id,
      user_name: userContext?.full_name || (userContext as any)?.email || currentUserData?.full_name || (user as any).email || "Sistema",
      timestamp: serverTimestamp(),
      company_id: data.company_id || userContext?.company_id || currentCompanyId
    };

    try {
      const newLogRef = doc(collection(db, "audit_logs"));
      await setDoc(newLogRef, logData);
    } catch (error: unknown) {
      if (error instanceof Error) {
        console.error("Error creating audit log:", error.message);
      }
    }
  },
};

import React, { createContext, useContext, useState, useEffect, useRef } from "react";
import { 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged,
  GoogleAuthProvider,
  signInWithPopup,
  User as FirebaseUser
} from "firebase/auth";
import { auth, db } from "./firebase";
import { doc, setDoc, serverTimestamp } from "firebase/firestore";
import { api } from "./api";

import { PermissionId, DEFAULT_ROLE_PERMISSIONS } from "./permissions";
import { User } from "../types";

export interface ExtendedUser extends User {
  permissions?: PermissionId[];
}

interface AuthContextType {
  user: ExtendedUser | null;
  login: (email: string, password: string) => Promise<void>;
  register: (data: any) => Promise<void>;
  loginWithGoogle: () => Promise<void>;
  logout: () => Promise<void>;
  isLoading: boolean;
  hasPermission: (permission: PermissionId) => boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const unsubscribeDocRef = useRef<(() => void) | null>(null);

  useEffect(() => {
    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        try {
          // Fetch user data from backend
          let userData = null;
          try {
            userData = await api.get("me");
          } catch (error) {
            console.error("Error fetching user data from backend:", error);
            // Fallback user object if backend fails
            userData = {
              id: firebaseUser.uid,
              email: firebaseUser.email,
              full_name: firebaseUser.email?.split("@")[0] || "Usuário",
              role: firebaseUser.email?.toLowerCase() === "sys.powercontrol@gmail.com" ? "master" : "user",
              company_id: null
            };
          }

          if (userData) {
            if (userData.company_id) {
              api.setCompanyId(userData.company_id);
            }
            api.setIsSystemAdmin(userData.role === "master");
            setUser(userData);
          }
          setIsLoading(false);
        } catch (error) {
          console.error("Critical error in AuthProvider:", error);
          setIsLoading(false);
        }
      } else {
        setUser(null);
        api.setCompanyId(null);
        api.setIsSystemAdmin(false);
        setIsLoading(false);
      }
    });

    return () => unsubscribeAuth();
  }, []);

  const login = async (email: string, password: string) => {
    await signInWithEmailAndPassword(auth, email, password);
  };

  const register = async (data: any) => {
    const { email, password, full_name, phone, cpf, invite_id } = data;

    let inviteData = null;
    if (invite_id) {
      try {
        const invite = await api.get("invites", invite_id);
        if (invite.status === "PENDING" && new Date(invite.expires_at) > new Date()) {
          inviteData = invite;
        }
      } catch (error) {
        console.error("Error validating invite during registration:", error);
      }
    }

    const isSystemAdmin = email?.toLowerCase() === "sys.powercontrol@gmail.com";

    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    const uid = userCredential.user.uid;

    const userData = {
      email,
      full_name,
      phone,
      cpf,
      role: inviteData ? inviteData.role : (isSystemAdmin ? "master" : "user"),
      is_active: true,
      company_id: inviteData ? inviteData.company_id : null,
      created_at: serverTimestamp()
    };

    await setDoc(doc(db, "users", uid), userData);

    if (inviteData) {
      await api.put("invites", invite_id, { status: "ACCEPTED" });
      api.setCompanyId(inviteData.company_id);
    }
  };

  const loginWithGoogle = async () => {
    const provider = new GoogleAuthProvider();
    await signInWithPopup(auth, provider);
  };

  const logout = async () => {
    await signOut(auth);
  };

  const hasPermission = (permission: PermissionId) => {
    if (!user) return false;
    if (user.role === 'master') return true;

    // Check user-specific permissions first
    if ((user as ExtendedUser).permissions?.includes(permission)) return true;

    // Fallback to role-based defaults if no specific permissions are set
    // In a real app, we'd fetch company.role_permissions here, but for now we use defaults
    const rolePermissions = DEFAULT_ROLE_PERMISSIONS[user.role] || [];
    return rolePermissions.includes(permission);
  };

  return (
    <AuthContext.Provider value={{ user, login, register, loginWithGoogle, logout, isLoading, hasPermission }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

import { format, parseISO } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { formatInTimeZone, toZonedTime } from 'date-fns-tz';

const TIMEZONE = 'America/Sao_Paulo';

/**
 * Formats a date string or Date object to a specific format in the Brasília timezone.
 * @param date The date to format (string, timestamp, or Date)
 * @param formatStr The date-fns format string (default: 'dd/MM/yyyy')
 */
export function formatBR(date: string | number | Date | null | undefined, formatStr: string = 'dd/MM/yyyy'): string {
  if (!date) return '';

  try {
    // If it's a YYYY-MM-DD string, append time to avoid UTC midnight shift
    let parsedDate: Date;
    if (typeof date === 'string') {
      if (date.length === 10) {
        // "YYYY-MM-DD" -> "YYYY-MM-DDT12:00:00" to safely fall in the correct day regardless of timezone
        parsedDate = new Date(`${date}T12:00:00`);
      } else {
        parsedDate = new Date(date);
      }
    } else {
      parsedDate = new Date(date);
    }

    if (isNaN(parsedDate.getTime())) return '';

    return formatInTimeZone(parsedDate, TIMEZONE, formatStr, { locale: ptBR });
  } catch (e) {
    console.error('Error formatting date:', date, e);
    return '';
  }
}

/**
 * Gets the current date/time in the Brasília timezone.
 */
export function getNowBR(): Date {
  return toZonedTime(new Date(), TIMEZONE);
}

/**
 * Gets the current date in YYYY-MM-DD format in the Brasília timezone.
 */
export function getTodayBR(): string {
  return formatInTimeZone(new Date(), TIMEZONE, 'yyyy-MM-dd');
}

