  TrendingDown,
  ArrowUpRight,
  ArrowDownLeft,
  Zap,
  Globe
} from "lucide-react";
import { 
  LineChart, 
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  BarChart,
  Bar,
  PieChart,
  Pie,
  Cell
} from "recharts";
import { Link } from "react-router-dom";

const COLORS = ['#2563EB', '#10B981', '#F59E0B', '#8B5CF6'];

const StatCard = ({ title, value, icon: Icon, color, subtitle }: any) => (
  <div className={`p-6 rounded-2xl bg-gradient-to-br ${color} text-white shadow-lg`}>
    <div className="flex justify-between items-start mb-4">
      <div className="p-3 bg-white/20 rounded-xl">
        <Icon size={24} className="text-white" />
      </div>
    </div>
    <h3 className="text-sm font-medium opacity-80">{title}</h3>
    <p className="text-3xl font-bold mt-1">{value}</p>
    <p className="text-xs mt-2 opacity-70">{subtitle}</p>
  </div>
);

export default function Dashboard() {
  const { user, hasPermission } = useAuth();
  const currentCompanyId = api.getCompanyId();



  const { data: salesData = [] } = useQuery({ 
    queryKey: ["sales", currentCompanyId], 
    queryFn: () => api.get("sales"),
    enabled: !!user
  });
  const { data: productsData = [] } = useQuery({ 
    queryKey: ["products", currentCompanyId], 
    queryFn: () => api.get("products"),
    enabled: !!user
  });
  const { data: clientsData = [] } = useQuery({ 
    queryKey: ["clients", currentCompanyId], 
    queryFn: () => api.get("clients"),
    enabled: !!user
  });
  const { data: cashiersData = [] } = useQuery({ 
    queryKey: ["cashiers", currentCompanyId], 
    queryFn: () => api.get("cashiers"),
    enabled: !!user
  });
  const { data: accountsPayableData = [] } = useQuery({ 
    queryKey: ["accountsPayable", currentCompanyId], 
    queryFn: () => api.get("accountsPayable"),
    enabled: !!user
  });
  const { data: accountsReceivableData = [] } = useQuery({ 
    queryKey: ["accountsReceivable", currentCompanyId], 
    queryFn: () => api.get("accountsReceivable"),
    enabled: !!user
  });
  const { data: purchasesData = [] } = useQuery({ 
    queryKey: ["purchases", currentCompanyId], 
    queryFn: () => api.get("purchases"),
    enabled: !!user
  });

  const sales = useMemo(() => {
    if (!currentCompanyId) return salesData;
    return salesData.filter((item: any) => item.company_id === currentCompanyId);
  }, [salesData, currentCompanyId]);

  const products = useMemo(() => {
    if (!currentCompanyId) return productsData;
    return productsData.filter((item: any) => item.company_id === currentCompanyId);
  }, [productsData, currentCompanyId]);

  const clients = useMemo(() => {
    if (!currentCompanyId) return clientsData;
    return clientsData.filter((item: any) => item.company_id === currentCompanyId);
  }, [clientsData, currentCompanyId]);

  const cashiers = useMemo(() => {
    if (!currentCompanyId) return cashiersData;
    return cashiersData.filter((item: any) => item.company_id === currentCompanyId);
  }, [cashiersData, currentCompanyId]);

  const accountsPayable = useMemo(() => {
    if (!currentCompanyId) return accountsPayableData;
    return accountsPayableData.filter((item: any) => item.company_id === currentCompanyId);
  }, [accountsPayableData, currentCompanyId]);

  const accountsReceivable = useMemo(() => {
    if (!currentCompanyId) return accountsReceivableData;
    return accountsReceivableData.filter((item: any) => item.company_id === currentCompanyId);
  }, [accountsReceivableData, currentCompanyId]);

  const purchases = useMemo(() => {
    if (!currentCompanyId) return purchasesData;
    return purchasesData.filter((item: any) => item.company_id === currentCompanyId);
  }, [purchasesData, currentCompanyId]);

  const totalSalesMonth = sales.reduce((acc: number, sale: any) => acc + (sale.total || 0), 0);
  const totalReceivable = accountsReceivable.filter((a: any) => a.status === "Pendente").reduce((acc: number, a: any) => acc + (a.amount || 0), 0);
  const totalPayable = accountsPayable.filter((a: any) => a.status === "Pendente").reduce((acc: number, a: any) => acc + (a.amount || 0), 0);
  const totalPurchases = purchases.reduce((acc: number, p: any) => acc + (p.total || 0), 0);
  const openCashiers = cashiers.filter((c: any) => c.status === "Aberto").length;
  const lowStockProducts = products.filter((p: any) => p.stock_quantity <= p.min_stock);

  // Generate chart data from last 7 days
  const last7Days = Array.from({ length: 7 }, (_, i) => {
    const d = getNowBR();
    d.setDate(d.getDate() - (6 - i));
    return formatBR(d, 'yyyy-MM-dd');
  });

  const chartData = last7Days.map(date => {
    const daySales = sales.filter((s: any) => s.sale_date && formatBR(s.sale_date, 'yyyy-MM-dd') === date);
    return {
      name: formatBR(date, 'dd/MM'),
      value: daySales.reduce((acc: number, s: any) => acc + (s.total || 0), 0)
    };
  });



  if (!hasPermission('dashboard.view')) {
    return <SellerDashboard />;
  }

  return (
    <div className="space-y-8">
      <div>
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
            <p className="text-gray-500">Olá, {user?.full_name?.split(' ')[0]}. Veja o que está acontecendo hoje.</p>
          </div>
          {user?.role === 'master' && (
            <Link 
              to="/DashboardGlobal"
              className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-colors shadow-lg shadow-blue-100"
            >
              <Globe size={20} />
              Dashboard Global
            </Link>
          )}
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Vendas do Mês" 
          value={`R$ ${totalSalesMonth.toLocaleString()}`} 
          icon={TrendingUp} 
          color="from-green-500 to-green-600"
          subtitle={`${sales.length} vendas realizadas`}
        />
        <StatCard 
          title="Compras do Mês" 
          value={`R$ ${totalPurchases.toLocaleString()}`} 
          icon={ShoppingCart} 
          color="from-orange-500 to-orange-600"
          subtitle={`${purchases.length} entradas de estoque`}
        />
        <StatCard 
          title="A Receber" 
          value={`R$ ${totalReceivable.toLocaleString()}`} 
          icon={ArrowUpRight} 
          color="from-blue-500 to-blue-600"
          subtitle="Contas pendentes"
        />
        <StatCard 
          title="A Pagar" 
          value={`R$ ${totalPayable.toLocaleString()}`} 
          icon={ArrowDownLeft} 
          color="from-red-500 to-red-600"
          subtitle="Compromissos pendentes"
        />
        <StatCard 
          title="Estoque Baixo" 
          value={lowStockProducts.length.toString()} 
          icon={AlertTriangle} 
          color="from-yellow-500 to-yellow-600"
          subtitle="Produtos p/ reposição"
        />
        <StatCard 
          title="Caixas Abertos" 
          value={openCashiers.toString()} 
          icon={Zap} 
          color="from-purple-500 to-purple-600"
          subtitle="Operações em curso"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h2 className="font-bold text-lg">Evolução de Vendas</h2>
            <div className="flex gap-2">
              <button className="px-3 py-1 text-xs font-medium bg-blue-50 text-blue-600 rounded-full">Este Mês</button>
              <button className="px-3 py-1 text-xs font-medium text-gray-500 hover:bg-gray-50 rounded-full">30 Dias</button>
            </div>
          </div>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F3F4F6" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9CA3AF'}} />
                <YAxis axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9CA3AF'}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                />
                <Line 
                  type="monotone" 
                  dataKey="value" 
                  stroke="#2563EB" 
                  strokeWidth={3} 
                  dot={{ r: 4, fill: '#2563EB', strokeWidth: 2, stroke: '#fff' }}
                  activeDot={{ r: 6, strokeWidth: 0 }}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Quick Actions & Low Stock */}
        <div className="space-y-8">
          <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
            <h2 className="font-bold text-lg mb-4">Ações Rápidas</h2>
            <div className="grid grid-cols-2 gap-4">
              <Link to="/Vender" className="flex flex-col items-center p-4 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-100 transition-colors">
                <ShoppingCart size={24} className="mb-2" />
                <span className="text-xs font-bold">Vender</span>
              </Link>
              <Link to="/Clientes" className="flex flex-col items-center p-4 bg-purple-50 text-purple-600 rounded-xl hover:bg-purple-100 transition-colors">
                <Users size={24} className="mb-2" />
                <span className="text-xs font-bold">Novo Cliente</span>
              </Link>
              <Link to="/Caixas" className="flex flex-col items-center p-4 bg-orange-50 text-orange-600 rounded-xl hover:bg-orange-100 transition-colors">
                <CreditCard size={24} className="mb-2" />
                <span className="text-xs font-bold">Caixas</span>
              </Link>
              <Link to="/ContasPagar" className="flex flex-col items-center p-4 bg-red-50 text-red-600 rounded-xl hover:bg-red-100 transition-colors">
                <TrendingDown size={24} className="mb-2" />
                <span className="text-xs font-bold">Pagar</span>
              </Link>
            </div>
          </div>

          {lowStockProducts.length > 0 && (
            <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
              <div className="flex items-center gap-2 text-red-600 mb-4">
                <AlertTriangle size={20} />
                <h2 className="font-bold text-lg">Estoque Baixo</h2>
              </div>
              <div className="space-y-4">
                {lowStockProducts.slice(0, 3).map((p: any) => (
                  <div key={p.id} className="flex justify-between items-center">
                    <div>
                      <p className="text-sm font-medium text-gray-900">{p.name}</p>
                      <p className="text-xs text-gray-500">{p.stock_quantity} un em estoque</p>
                    </div>
                    <Link to="/Produtos" className="text-blue-600 hover:text-blue-700">
                      <ArrowRight size={16} />
                    </Link>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Recent Sales */}
      <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
        <div className="flex justify-between items-center mb-6">
          <h2 className="font-bold text-lg">Vendas Recentes</h2>
          <Link to="/HistoricoVendas" className="text-sm text-blue-600 font-medium">Ver todas</Link>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-xs text-gray-500 uppercase tracking-wider border-b border-gray-50">
                <th className="pb-4 font-medium">Número</th>
                <th className="pb-4 font-medium">Cliente</th>
                <th className="pb-4 font-medium">Total</th>
                <th className="pb-4 font-medium">Status</th>
                <th className="pb-4 font-medium">Data</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {[...sales].sort((a: any, b: any) => new Date(b.sale_date).getTime() - new Date(a.sale_date).getTime()).slice(0, 5).map((sale: any) => (
                <tr key={sale.id} className="text-sm">
                  <td className="py-4 font-medium text-gray-900">#{sale.sale_number || "001"}</td>
                  <td className="py-4 text-gray-600">{sale.client_name || "Consumidor Final"}</td>
                  <td className="py-4 font-bold text-green-600">R$ {sale.total?.toLocaleString()}</td>
                  <td className="py-4">
                    <span className="px-2 py-1 bg-green-100 text-green-700 rounded-full text-[10px] font-bold uppercase">
                      {sale.status || "Concluída"}
                    </span>
                  </td>
                  <td className="py-4 text-gray-500">{formatBR(sale.sale_date)}</td>
                </tr>
              ))}
              {sales.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-8 text-center text-gray-500">Nenhuma venda realizada hoje.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import React, { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { api } from "../lib/api";
import { useAuth } from "../lib/auth";
import { ALL_PERMISSIONS, PermissionId } from "../lib/permissions";
import { 
  UserPlus, 
  Search, 
  Edit, 
  UserMinus,
  Mail,
  Shield,
  ShieldCheck,
  BadgeCheck,
  Building2,
  Crown,
  Phone,
  FileText,
  ChevronDown,
  ChevronUp
} from "lucide-react";
import { toast } from "sonner";
import ConfirmationModal from "../components/ConfirmationModal";
import { InputMask } from "../components/ui/InputMask";

export default function Employees() {
  const { user, hasPermission } = useAuth();
  const queryClient = useQueryClient();
  const [searchTerm, setSearchTerm] = useState("");

  const canManage = hasPermission('employees.manage');



  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<any>(null);
  const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);
  const [employeeToUnlink, setEmployeeToUnlink] = useState<string | null>(null);
  const [isUnlinking, setIsUnlinking] = useState(false);
  const [showPermissions, setShowPermissions] = useState(false);
  const [selectedPermissions, setSelectedPermissions] = useState<PermissionId[]>([]);

  const currentCompanyId = user?.company_id || api.getCompanyId();

  const { data: employees = [], isLoading } = useQuery({ 
    queryKey: ["employees", currentCompanyId], 
    queryFn: () => api.get("users"),
    enabled: !!currentCompanyId
  });

  const filteredEmployees = employees.filter((e: any) => 
    e.full_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    e.email?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const employeeMutation = useMutation({
    mutationFn: (data: any) => api.put("users", editingEmployee.id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["employees", currentCompanyId] });
      toast.success("Funcionário atualizado!");
      setIsModalOpen(false);
      setEditingEmployee(null);
    }
  });

  const linkMutation = useMutation({
    mutationFn: async (email: string) => {
      const foundUser: any = await api.findUserByEmail(email);
      if (!foundUser) throw new Error("Usuário não encontrado com este e-mail.");
      if (foundUser.company_id) throw new Error("Este usuário já está vinculado a uma empresa.");

      return api.put("users", foundUser.id, { company_id: currentCompanyId });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["employees", currentCompanyId] });
      toast.success("Funcionário vinculado com sucesso!");
      setIsModalOpen(false);
    },
    onError: (error: any) => {
      toast.error(error.message || "Erro ao vincular funcionário.");
    }
  });

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const data = Object.fromEntries(formData.entries());

    if (editingEmployee) {
      employeeMutation.mutate({ 
        ...data, 
        active: data.active === "on",
        permissions: selectedPermissions
      });
    } else {
      linkMutation.mutate(data.email as string);
    }
  };

  const handleUnlink = async () => {
    if (!employeeToUnlink) return;

    setIsUnlinking(true);
    try {
      await api.put("users", employeeToUnlink, { company_id: null });
      queryClient.invalidateQueries({ queryKey: ["employees", currentCompanyId] });
      toast.success("Funcionário desvinculado!");
      setIsConfirmModalOpen(false);
      setEmployeeToUnlink(null);
    } catch (error) {
      toast.error("Erro ao desvincular funcionário.");
    } finally {
      setIsUnlinking(false);
    }
  };

if (!canManage) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-4">
        <div className="p-4 bg-red-50 text-red-600 rounded-full">
          <Shield size={48} />
        </div>
        <h1 className="text-2xl font-bold text-gray-900">Acesso Restrito</h1>
        <p className="text-gray-500 max-w-md">
          Esta página é restrita a usuários autorizados. Entre em contato com o administrador para solicitar acesso.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Funcionários</h1>
          <p className="text-gray-500">Gerencie os usuários vinculados à sua empresa.</p>
        </div>
        <button 
          onClick={() => {
            setEditingEmployee(null);
            setIsModalOpen(true);
          }}
          className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-shadow shadow-lg shadow-blue-200"
        >
          <UserPlus size={20} />
          Vincular Funcionário
        </button>
      </div>

      {/* Search */}
      <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input 
            type="text" 
            placeholder="Buscar por nome ou e-mail..." 
            className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      {/* Employees Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {isLoading ? (
          <div className="col-span-full py-12 text-center text-gray-500">Carregando funcionários...</div>
        ) : filteredEmployees.length === 0 ? (
          <div className="col-span-full py-12 text-center text-gray-400 bg-white rounded-2xl border border-gray-100">
            Nenhum funcionário encontrado.
          </div>
        ) : filteredEmployees.map((employee: any) => (
          <div key={employee.id} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow group relative">
            <div className="flex justify-between items-start mb-4">
              <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center font-bold text-lg overflow-hidden">
                {employee.photo_url ? (
                  <img src={employee.photo_url} alt={employee.full_name} className="w-full h-full object-cover" />
                ) : (
                  employee.full_name?.charAt(0) || "U"
                )}
              </div>
              <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => {
                    setEditingEmployee(employee);
                    setSelectedPermissions(employee.permissions || []);
                    setShowPermissions(false);
                    setIsModalOpen(true);
                  }}
                  className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                >
                  <Edit size={18} />
                </button>
                {employee.id !== user?.id && (
                  <button 
                    onClick={() => {
                      setEmployeeToUnlink(employee.id);
                      setIsConfirmModalOpen(true);
                    }}
                    className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                  >
                    <UserMinus size={18} />
                  </button>
                )}
              </div>
            </div>

            <h3 className="font-bold text-lg text-gray-900 mb-1 flex items-center gap-2">
              {employee.full_name}
              {employee.active && <BadgeCheck size={18} className="text-blue-500" />}
            </h3>

            <div className="space-y-2 mt-4">
              <div className="flex items-center gap-2 text-sm text-gray-500">
                <Mail size={16} />
                <span className="truncate">{employee.email}</span>
              </div>
              {employee.phone && (
                <div className="flex items-center gap-2 text-sm text-gray-500">
                  <Phone size={16} />
                  <span>{employee.phone}</span>
                </div>
              )}
              {employee.document && (
                <div className="flex items-center gap-2 text-sm text-gray-500">
                  <FileText size={16} />
                  <span>{employee.document}</span>
                </div>
              )}
              <div className="flex items-center gap-2 text-sm text-gray-500">
                <Shield size={16} />
                <span className="flex items-center gap-1">
                  {employee.role === 'master' ? (
                    <span className="text-red-600 font-bold flex items-center gap-1"><Crown size={12} /> Admin Master</span>
                  ) : employee.role === 'admin' ? (
                    <span className="text-purple-600 font-bold flex items-center gap-1"><ShieldCheck size={12} /> Admin Empresa</span>
                  ) : (
                    employee.role || "Funcionário"
                  )}
                </span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modal Vincular/Editar Funcionário */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setIsModalOpen(false)} />
          <div className="relative bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center">
              <h2 className="text-xl font-bold">{editingEmployee ? "Editar Funcionário" : "Vincular Novo Funcionário"}</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              {!editingEmployee ? (
                <div className="space-y-4">
                  <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100 flex gap-3">
                    <Building2 className="text-blue-600 shrink-0" size={24} />
                    <p className="text-sm text-blue-800">
                      Para vincular um funcionário, ele já deve ter acessado o sistema pelo menos uma vez com o e-mail informado.
                    </p>
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-700">E-mail do Usuário *</label>
                    <input 
                      name="email" 
                      type="email"
                      required 
                      placeholder="email@exemplo.com"
                      className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" 
                    />
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-700">Nome</label>
                    <input 
                      name="full_name"
                      defaultValue={editingEmployee.full_name}
                      className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" 
                    />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-sm font-bold text-gray-700">Telefone</label>
                      <InputMask 
                        name="phone"
                        mask="(00) 00000-0000"
                        defaultValue={editingEmployee.phone}
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-sm font-bold text-gray-700">CPF</label>
                      <InputMask 
                        name="document"
                        mask="000.000.000-00"
                        defaultValue={editingEmployee.document}
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-700">Nível de Acesso</label>
                    <select 
                      name="role" 
                      defaultValue={editingEmployee.role}
                      className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" 
                    >
                      <option value="user">Funcionário (Vendedor)</option>
                      <option value="admin">Admin Empresa (Acesso Total)</option>
                    </select>
                  </div>
                  <div className="flex items-center gap-2 pt-2">
                    <input 
                      type="checkbox" 
                      name="active" 
                      id="active" 
                      defaultChecked={editingEmployee.active}
                      className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500"
                    />
                    <label htmlFor="active" className="text-sm font-bold text-gray-700">Usuário Ativo</label>
                  </div>

                  <div className="pt-4 border-t border-gray-100">
                    <button 
                      type="button"
                      onClick={() => setShowPermissions(!showPermissions)}
                      className="flex items-center justify-between w-full p-3 bg-gray-50 rounded-xl text-sm font-bold text-gray-700 hover:bg-gray-100 transition-colors"
                    >
                      <div className="flex items-center gap-2">
                        <ShieldCheck size={18} className="text-purple-600" />
                        Permissões Individuais
                      </div>
                      {showPermissions ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </button>

                    {showPermissions && (
                      <div className="mt-4 grid grid-cols-1 gap-2 max-h-48 overflow-y-auto pr-2">
                        {ALL_PERMISSIONS.map(p => (
                          <label key={p.id} className="flex items-center gap-3 p-2 hover:bg-gray-50 rounded-lg cursor-pointer transition-colors">
                            <input 
                              type="checkbox"
                              checked={selectedPermissions.includes(p.id)}
                              onChange={(e) => {
                                if (e.target.checked) {
                                  setSelectedPermissions([...selectedPermissions, p.id]);
                                } else {
                                  setSelectedPermissions(selectedPermissions.filter(id => id !== p.id));
                                }
                              }}
                              className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500"
                            />
                            <div>
                              <p className="text-xs font-bold text-gray-900">{p.name}</p>
                              <p className="text-[10px] text-gray-500">{p.category}</p>
                            </div>
                          </label>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              )}

              <div className="flex justify-end gap-3 pt-6">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-2 text-gray-500 font-bold">Cancelar</button>
                <button 
                  type="submit" 
                  disabled={employeeMutation.isPending || linkMutation.isPending} 
                  className="px-8 py-2 bg-blue-600 text-white rounded-xl font-bold shadow-lg shadow-blue-100"
                >
                  {employeeMutation.isPending || linkMutation.isPending ? "Processando..." : editingEmployee ? "Salvar" : "Vincular"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <ConfirmationModal
        isOpen={isConfirmModalOpen}
        onClose={() => setIsConfirmModalOpen(false)}
        onConfirm={handleUnlink}
        title="Desvincular Funcionário"
        message="Tem certeza que deseja desvincular este funcionário da sua empresa? Ele perderá o acesso aos dados da empresa."
        isLoading={isUnlinking}
      />
    </div>
  );
}

import React, { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { api } from "../lib/api";
import { useAuth } from "../lib/auth";
import { formatBR } from "../lib/dateUtils";
import { 
  FileText, 
  Plus, 
  Search, 
  MoreVertical, 
  Download, 
  Send,
  CheckCircle2,
  AlertCircle,
  Clock,
  Printer,
  XCircle,
  Shield
} from "lucide-react";
import { toast } from "sonner";
import NfeStatusBadge, { NfeStatus } from "../components/NfeStatusBadge";
import DanfeViewer from "../components/DanfeViewer";
import { fiscalApi } from "../services/fiscalApi";
import ExportButton from "../components/ExportButton";

import { Link } from "react-router-dom";

export default function Fiscal() {
  const queryClient = useQueryClient();
  const { user, hasPermission } = useAuth();
  const [searchTerm, setSearchTerm] = useState("");

  const canManage = hasPermission('fiscal.manage');



  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDanfeOpen, setIsDanfeOpen] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<any>(null);
  const [invoices, setInvoices] = useState<any[]>([]);
  const [isLoadingInvoices, setIsLoadingInvoices] = useState(true);

  const currentCompanyId = user?.company_id || api.getCompanyId();

  React.useEffect(() => {
    if (!currentCompanyId) return;
    const unsubscribe = api.subscribe("invoices", { company_id: currentCompanyId }, (data) => {
      setInvoices(data);
      setIsLoadingInvoices(false);
    });
    return () => unsubscribe();
  }, [currentCompanyId]);

  const { data: sales = [] } = useQuery({
    queryKey: ["sales", currentCompanyId],
    queryFn: () => api.get("sales"),
    enabled: !!(currentCompanyId || canManage)
  });

  const filteredInvoices = invoices.filter((i: any) => 
    (i.number?.toString() || "").includes(searchTerm) ||
    (i.client_name?.toLowerCase() || "").includes(searchTerm.toLowerCase())
  );

  const invoiceExportHeaders = {
    number: "Número",
    series: "Série",
    client_name: "Cliente",
    total_value: "Valor Total",
    status: "Status",
    created_at: "Data Emissão",
    access_key: "Chave de Acesso"
  };

  const cancelMutation = useMutation({
    mutationFn: async (invoice: any) => {
      if (!company?.fiscal_token || !invoice.reference) {
        // Fallback for simulated notes or missing config
        return api.put("invoices", invoice.id, { status: "Cancelada" });
      }

      const fiscalConfig = {
        token: company.fiscal_token,
        environment: company.fiscal_environment || "sandbox",
        provider: company.fiscal_provider || "FocusNFe"
      };

      const reason = window.prompt("Motivo do cancelamento (mínimo 15 caracteres):", "Erro na digitação dos dados da venda");
      if (!reason || reason.length < 15) {
        throw new Error("O motivo do cancelamento deve ter pelo menos 15 caracteres.");
      }

      const result = await fiscalApi.cancel(fiscalConfig as any, invoice.reference, reason);

      if (result.status === "sucesso" || result.status === "cancelado") {
        return api.put("invoices", invoice.id, { status: "Cancelada" });
      } else {
        throw new Error(result.message || "Erro ao cancelar nota no provedor");
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["invoices"] });
      toast.success("Nota Fiscal cancelada com sucesso!");
    },
    onError: (error: any) => {
      toast.error(`Erro ao cancelar: ${error.message}`);
    }
  });

  const { data: company } = useQuery({
    queryKey: ["company", currentCompanyId],
    queryFn: () => api.get("companies", currentCompanyId),
    enabled: !!currentCompanyId
  });

  const { data: clients = [] } = useQuery({
    queryKey: ["clients", currentCompanyId],
    queryFn: () => api.get("clients"),
    enabled: !!currentCompanyId
  });

  const emitMutation = useMutation({
    mutationFn: async (data: any) => {
      const sale = sales.find((s: any) => s.id === data.sale_id);
      if (!sale) throw new Error("Venda não encontrada");

      const client = clients.find((c: any) => c.id === sale.client_id) || { name: sale.client_name };

      if (!company?.fiscal_token) {
        throw new Error("Token fiscal não configurado. Vá em Configurações > Fiscal.");
      }

      const fiscalConfig = {
        token: company.fiscal_token,
        environment: company.fiscal_environment || "sandbox",
        provider: company.fiscal_provider || "FocusNFe"
      };

      const result = await fiscalApi.emit(fiscalConfig as any, {
        sale_id: sale.id,
        type: data.type,
        client,
        items: sale.items,
        total: sale.total,
        company
      });

      return api.post("invoices", {
        ...data,
        company_id: currentCompanyId,
        number: result.protocol ? parseInt(result.protocol.slice(-6)) : Math.floor(Math.random() * 90000),
        series: "001",
        client_name: sale.client_name,
        client_document: sale.client_document || "Consumidor Final",
        total: sale.total,
        status: result.status === "processando" ? "Pendente" : "Emitida",
        emission_date: new Date().toISOString(),
        reference: result.reference,
        protocol: result.protocol,
        access_key: result.access_key
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["invoices"] });
      toast.success("Nota Fiscal enviada para processamento!");
      setIsModalOpen(false);
    },
    onError: (error: any) => {
      toast.error(`Erro na emissão: ${error.message}`);
    }
  });

  const checkStatusMutation = useMutation({
    mutationFn: async (invoice: any) => {
      if (!company?.fiscal_token || !invoice.reference) return;

      const fiscalConfig = {
        token: company.fiscal_token,
        environment: company.fiscal_environment || "sandbox",
        provider: company.fiscal_provider || "FocusNFe"
      };

      const result = await fiscalApi.checkStatus(fiscalConfig as any, invoice.reference, invoice.type);

      let newStatus = invoice.status;
      let xmlStorageUrl = invoice.xml_storage_url;

      if (result.status === "autorizado") {
        newStatus = "Emitida";

        // Persist XML to Storage if not already done
        if (!xmlStorageUrl && result.xml_url && result.access_key) {
          try {
            xmlStorageUrl = await fiscalApi.saveXmlToStorage(
              currentCompanyId,
              result.access_key,
              result.xml_url
            );
          } catch (e) {
            console.error("Failed to persist XML:", e);
          }
        }
      }

      if (result.status === "erro_autorizacao") newStatus = "Erro";
      if (result.status === "cancelado") newStatus = "Cancelada";

      return api.put("invoices", invoice.id, {
        status: newStatus,
        protocol: result.protocol || invoice.protocol,
        access_key: result.access_key || invoice.access_key,
        xml_url: result.xml_url,
        xml_storage_url: xmlStorageUrl,
        pdf_url: result.pdf_url,
        error_message: result.error_message
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["invoices"] });
      toast.success("Status da nota atualizado!");
    },
    onError: (error: any) => {
      console.error("Erro ao verificar status da nota:", error);
      toast.error(error.message || "Falha ao consultar status da nota fiscal. Tente novamente.");
    }
  });

  const handleEmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const data = Object.fromEntries(formData.entries());
    emitMutation.mutate(data);
  };

if (!canManage) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-4">
        <div className="p-4 bg-red-50 text-red-600 rounded-full">
          <Shield size={48} />
        </div>
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Acesso Restrito</h2>
          <p className="text-gray-500 max-w-md mx-auto">
            Você não tem permissão para visualizar os dados fiscais. 
            Esta página é restrita a usuários autorizados.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Fiscal (NF-e / NFC-e)</h1>
          <p className="text-gray-500">Emissão e controle de Notas Fiscais Eletrônicas.</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <div className="flex gap-2">
            <ExportButton 
              data={filteredInvoices} 
              filename="notas-fiscais" 
              format="xlsx" 
              headers={invoiceExportHeaders} 
            />
            <ExportButton 
              data={filteredInvoices} 
              filename="notas-fiscais" 
              format="pdf" 
              title="Relatório de Notas Fiscais"
              headers={invoiceExportHeaders} 
            />
          </div>
          <Link 
            to="/Certificado"
            className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-700 rounded-xl font-bold hover:bg-gray-50 transition-all"
          >
            <Shield size={20} className="text-blue-600" />
            Certificado Digital
          </Link>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-shadow shadow-lg shadow-blue-200"
          >
            <Plus size={20} />
            Emitir Nova Nota
          </button>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: "Emitidas (Mês)", value: "124", color: "text-blue-600", bg: "bg-blue-50", icon: CheckCircle2 },
          { label: "Aguardando", value: "12", color: "text-orange-600", bg: "bg-orange-50", icon: Clock },
          { label: "Rejeitadas", value: "2", color: "text-red-600", bg: "bg-red-50", icon: AlertCircle },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-4">
            <div className={`p-3 rounded-2xl ${stat.bg} ${stat.color}`}>
              <stat.icon size={24} />
            </div>
            <div>
              <p className="text-sm font-bold text-gray-500 uppercase tracking-wider">{stat.label}</p>
              <p className={`text-2xl font-extrabold ${stat.color}`}>{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Search */}
      <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input 
            type="text" 
            placeholder="Buscar por número da nota ou cliente..." 
            className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      {/* Invoices Table */}
      <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-100">
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Número / Série</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Cliente</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Data Emissão</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Valor Total</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {isLoadingInvoices ? (
                <tr><td colSpan={6} className="px-6 py-12 text-center text-gray-500">Carregando notas...</td></tr>
              ) : filteredInvoices.length === 0 ? (
                <tr><td colSpan={6} className="px-6 py-12 text-center text-gray-400">Nenhuma nota fiscal encontrada.</td></tr>
              ) : filteredInvoices.map((invoice: any) => (
                <tr key={invoice.id} className="hover:bg-gray-50 transition-colors group">
                  <td className="px-6 py-4">
                    <p className="font-bold text-gray-900">#{invoice.number || "---"}</p>
                    <p className="text-xs text-gray-500">Série: {invoice.series || "001"}</p>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-sm font-semibold text-gray-700">{invoice.client_name || "Consumidor Final"}</p>
                    <p className="text-xs text-gray-500">{invoice.client_document || "---"}</p>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-sm text-gray-600">{formatBR(invoice.emission_date)}</p>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-sm font-bold text-gray-900">R$ {invoice.total?.toLocaleString()}</p>
                  </td>
                  <td className="px-6 py-4">
                    <NfeStatusBadge status={invoice.status as NfeStatus} />
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      {invoice.status === "Pendente" && (
                        <button 
                          onClick={() => checkStatusMutation.mutate(invoice)}
                          className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" 
                          title="Sincronizar Status"
                        >
                          <Clock size={18} />
                        </button>
                      )}
                      <button 
                        onClick={() => {
                          setSelectedInvoice(invoice);
                          setIsDanfeOpen(true);
                        }}
                        className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" 
                        title="Imprimir DANFE"
                        disabled={!invoice.pdf_url && invoice.status !== "Emitida"}
                      >
                        <Printer size={18} />
                      </button>
                      {(invoice.xml_storage_url || invoice.xml_url) && (
                        <a 
                          href={invoice.xml_storage_url || invoice.xml_url} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" 
                          title={invoice.xml_storage_url ? "Baixar XML (Armazenamento Seguro)" : "Baixar XML (Link Externo)"}
                        >
                          <Download size={18} />
                        </a>
                      )}
                      <button className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" title="Enviar por E-mail">
                        <Send size={18} />
                      </button>
                      <button 
                        onClick={() => {
                          cancelMutation.mutate(invoice);
                        }}
                        className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors" 
                        title="Cancelar Nota"
                        disabled={invoice.status === "Cancelada"}
                      >
                        <XCircle size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal Emitir Nota */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setIsModalOpen(false)} />
          <div className="relative bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center">
              <h2 className="text-xl font-bold">Emitir Nota Fiscal</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">✕</button>
            </div>
            <form onSubmit={handleEmit} className="p-6 space-y-4">
              <div className="space-y-2">
                <label className="text-sm font-bold text-gray-700">Venda de Origem</label>
                <select name="sale_id" required className="w-full px-4 py-2 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500">
                  <option value="">Selecione uma venda...</option>
                  {sales.filter((s: any) => s.status === "Concluída").map((s: any) => (
                    <option key={s.id} value={s.id}>
                      Venda #{s.sale_number} - R$ {s.total?.toLocaleString()} ({s.client_name})
                    </option>
                  ))}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-bold text-gray-700">Tipo de Nota</label>
                <div className="grid grid-cols-2 gap-4">
                  <label className="flex items-center gap-2 p-3 border border-gray-200 rounded-xl cursor-pointer hover:bg-gray-50">
                    <input type="radio" name="type" value="NFe" defaultChecked className="text-blue-600" />
                    <span className="text-sm font-bold">NF-e (Produtos)</span>
                  </label>
                  <label className="flex items-center gap-2 p-3 border border-gray-200 rounded-xl cursor-pointer hover:bg-gray-50">
                    <input type="radio" name="type" value="NFCe" className="text-blue-600" />
                    <span className="text-sm font-bold">NFC-e (Consumidor)</span>
                  </label>
                </div>
              </div>
              <div className="p-4 bg-blue-50 rounded-2xl flex items-start gap-3">
                <AlertCircle className="text-blue-600 shrink-0" size={20} />
                <p className="text-xs text-blue-700 leading-relaxed">
                  A emissão de notas fiscais requer um certificado digital A1 válido e configurado no sistema. 
                  Certifique-se de que os dados fiscais do cliente e dos produtos estão completos.
                </p>
              </div>
              <div className="flex justify-end gap-3 pt-6">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-2 text-gray-500 font-bold">Cancelar</button>
                <button type="submit" disabled={emitMutation.isPending} className="px-8 py-2 bg-blue-600 text-white rounded-xl font-bold shadow-lg shadow-blue-200">
                  {emitMutation.isPending ? "Emitindo..." : "Emitir Nota"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <DanfeViewer 
        isOpen={isDanfeOpen} 
        onClose={() => setIsDanfeOpen(false)} 
        pdfUrl={selectedInvoice?.pdf_url} 
        invoiceNumber={selectedInvoice?.number} 
      />
    </div>
  );
}

import React, { useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
