import { useAuth } from "../lib/auth";
import { formatBR, getNowBR } from "../lib/dateUtils";
import { 
  TrendingUp, 
  Building2, 
  Users, 
  DollarSign,
  ArrowUpRight,
  BarChart3,
  PieChart as PieChartIcon,
  Globe
} from "lucide-react";
