  Plus, 
  Trash2, 
  CheckCircle2,
  QrCode,
  Printer,
  ChevronRight,
  Search,
  Minus,
  AlertCircle,
  Tag,
  Package,
  Lock,
  CreditCard
} from "lucide-react";
